8	import Foundation
9	import SwiftUI
10	import Combine
11	
12	@Observable
13	final class DoseSettings: Codable {
14	    
15	    var backgroundLevel: BackgroundLevel
16	    var backgroundHandling: BackgroundHandling
17	    
18	    var personalDoseRange: DoseRange
19	    var historyDoseRange: DoseRange
20	    
21	    var annualBackgroundSubstractValue: Decimal
22	    var annualBackgroundIncludeValue: Decimal
23	    
24	    @ObservationIgnored
25	    var personalDoseReferenceValue: Float {
26	        annualValue / personalDoseRange.rangeReferenceInterval
27	    }
28	    
29	    @ObservationIgnored
30	    var historyDoseReferenceValue: Float {
31	        annualValue / historyDoseRange.barReferenceInterval
32	    }
33	
34	    init(
35	        backgroundLevel: BackgroundLevel,
36	        backgroundHandling: BackgroundHandling,
37	        personalDoseRange: DoseRange = .day,
38	        historyDoseRange: DoseRange = .day,
39	        annualBackgroundSubstractValue: Decimal = 1000,
40	        annualBackgroundIncludeValue: Decimal = 2500
41	    ) {
42	        self.backgroundLevel = backgroundLevel
43	        self.backgroundHandling = backgroundHandling
44	        self.personalDoseRange = personalDoseRange
45	        self.historyDoseRange = historyDoseRange
46	        self.annualBackgroundSubstractValue = annualBackgroundSubstractValue
47	        self.annualBackgroundIncludeValue = annualBackgroundIncludeValue
48	    }
49	    
50	    var annualValue: Float {
51	        switch backgroundHandling {
52	        case .substract:
53	            annualBackgroundSubstractValue.floatValue
54	        case .include:
55	            annualBackgroundIncludeValue.floatValue
56	        }
57	    }
58	    
59	    private enum CodingKeys: String, CodingKey {
60	        case backgroundLevel
61	        case backgroundHandling
62	        case personalDoseRange
63	        case historyDoseRange
64	        case annualBackgroundSubstractValue
65	        case annualBackgroundIncludeValue
66	    }
67	    
68	    init(from decoder: any Decoder) throws {
69	        let container = try decoder.container(keyedBy: CodingKeys.self)
70	        backgroundLevel = try container.decode(BackgroundLevel.self, forKey: .backgroundLevel)
71	        backgroundHandling = try container.decode(BackgroundHandling.self, forKey: .backgroundHandling)
72	        personalDoseRange = try container.decode(DoseRange.self, forKey: .personalDoseRange)
73	        historyDoseRange = try container.decode(DoseRange.self, forKey: .historyDoseRange)
74	        annualBackgroundSubstractValue = try container.decode(Decimal.self, forKey: .annualBackgroundSubstractValue)
75	        annualBackgroundIncludeValue = try container.decode(Decimal.self, forKey: .annualBackgroundIncludeValue)
76	    }
77	    
78	    func encode(to encoder: Encoder) throws {
79	        var container = encoder.container(keyedBy: CodingKeys.self)
80	        try container.encode(backgroundLevel, forKey: .backgroundLevel)
81	        try container.encode(backgroundHandling, forKey: .backgroundHandling)
82	        try container.encode(personalDoseRange, forKey: .personalDoseRange)
83	        try container.encode(historyDoseRange, forKey: .historyDoseRange)
84	        try container.encode(annualBackgroundSubstractValue, forKey: .annualBackgroundSubstractValue)
85	        try container.encode(annualBackgroundIncludeValue, forKey: .annualBackgroundIncludeValue)
86	    }
87	}
88	
89	extension DoseSettings {
90	    
91	    struct BackgroundLevel: Codable {
92	        enum Mode: Codable, Equatable {
93	            case manual
94	            case auto(coordinates: Coordinates, date: Date)
95	        }
96	        
97	        let value: Decimal
98	        let mode: Mode
99	        
100	        var title: LocalizedStringResource {
101	            switch mode {
102	            case .manual: .Dose.manualSettings
103	            case .auto: .Dose.autoForYourLocation
104	            }
105	        }
106	        
107	        var isAuto: Bool {
108	            switch mode {
109	            case .manual: false
110	            case .auto: true
111	            }
112	        }
113	    }
114	    
115	    enum BackgroundHandling: Codable, Identifiable {
116	        case substract
117	        case include
118	        
119	        var title: LocalizedStringResource {
120	            switch self {
121	            case .substract: .Dose.subtractBackground
122	            case .include: .Dose.includeBackground
123	            }
124	        }
125	        
126	        var description: LocalizedStringResource {
127	            switch self {
128	            case .substract: .Dose.showDoseOnlyAboveBackground
129	            case .include: .Dose.naturalBackgroundTechnogenicDose
130	            }
131	        }
132	        
133	        var id: Self { self }
134	    }
135	}
136	
137	enum DoseRange: String, OptionsPickerProtocol, Codable, Comparable {
138	    case day
139	    case week
140	    case month
141	    case halfYear
142	    case year
143	    
144	    var title: LocalizedStringResource {
145	        switch self {
146	        case .day: .Dose.dailyShort
147	        case .week: .Dose.weeklyShort
148	        case .month: .Dose.monthlyShort
149	        case .halfYear: .Dose.sixMonthShort
150	        case .year: .Dose.annualShort
151	        }
152	    }
153	    
154	    var description: LocalizedStringResource {
155	        switch self {
156	        case .day: .Dose.lastDay
157	        case .week: .Dose.lastWeek
158	        case .month: .Dose.lastMonth
159	        case .halfYear: .Dose.lastHalfYear
160	        case .year: .Dose.lastYear
161	        }
162	    }
163	    
164	    var info: LocalizedStringResource {
165	        switch self {
166	        case .day: .Dose.daily
167	        case .week: .Dose.weekly
168	        case .month: .Dose.monthly
169	        case .halfYear: .Dose.sixMonth
170	        case .year: .Dose.annual
171	        }
172	    }
173	    
174	    var rangeReferenceInterval: Float {
175	        switch self {
176	        case .day: 365
177	        case .week: 52
178	        case .month: 12
179	        case .halfYear: 2
180	        case .year: 1
181	        }
182	    }
183	    
184	    var barReferenceInterval: Float {
185	        switch self {
186	        case .day: 365.0 * 24.0
187	        case .week: 365.0
188	        case .month: 365.0
189	        case .halfYear: 52
190	        case .year: 12.0
191	        }
192	    }
193	    
194	    static func < (lhs: DoseRange, rhs: DoseRange) -> Bool {
195	        lhs.sortWeightDays < rhs.sortWeightDays
196	    }
197	
198	    private var sortWeightDays: Int {
199	        switch self {
200	        case .day: 1
201	        case .week: 7
202	        case .month: 30
203	        case .halfYear: 182
204	        case .year: 365
205	        }
206	    }
207	}
208	
